  font-weight: normal;
  font-style: normal;
}
html,
body {
  margin: 0;
  padding: 0;
}

.report-wrapper {
  --border-radius: 0.3em;
  --color-border: rgba(0, 0, 0, 0.1);
  --color-shadow: rgba(0, 0, 0, 0.1);
  --gap: 0.5rem;
  --padding: 0.35rem;
  box-sizing: border-box;
  font-family: "AnekLatin", "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  font-size: 11pt;
}
.report-wrapper dl {
  display: block;
  margin: 0;
  padding: 0;
}
