  margin: 0;
}
.report-wrapper .no-break {
  break-inside: avoid;
  -webkit-column-break-inside: avoid;
  page-break-inside: avoid;
  display: block;
}
@media screen {
  .report-container {
    width: 21cm;
  }
}
